INSERT INTO `counseling_records` VALUES (1,1,946,'Akademik','Kesulitan Memahami Materi Matematika','Siswa mengalami kesulitan dalam memahami konsep integral. Perlu pendampingan tambahan.','Koordinasi dengan guru mapel untuk les tambahan.','2026-10-01','2026-05-12 07:12:04'),(2,1,959,'Sosial','Konflik dengan Teman Sekelas','Terjadi kesalahpahaman dengan teman satu kelas terkait tugas kelompok.','Mediasi antara kedua pihak dan pembinaan komunikasi.','2026-10-04','2026-05-12 07:12:04'),(3,1,972,'Pribadi','Motivasi Belajar Menurun','Siswa terlihat kurang semangat dan sering mengantuk di kelas.','Konseling individu dan koordinasi dengan orang tua.','2026-10-07','2026-05-12 07:12:04'),(4,1,985,'Karir','Konsultasi Pemilihan Jurusan Kuliah','Siswa bingung memilih antara jurusan teknik atau kedokteran.','Tes minat bakat dan diskusi prospek karir.','2026-10-10','2026-05-12 07:12:04'),(5,1,998,'Akademik','Nilai Ulangan Harian Menurun','Prestasi akademik menurun sejak semester ini.','Evaluasi metode belajar dan penjadwalan ulang.','2026-10-13','2026-05-12 07:12:04'),(6,1,1011,'Sosial','Kesulitan Beradaptasi di Kelas Baru','Siswa pindahan merasa kesulitan bergaul dengan teman baru.','Buddy system dan kegiatan ice breaking.','2026-10-16','2026-05-12 07:12:04'),(7,1,1024,'Pribadi','Kecemasan Menghadapi Ujian','Siswa mengalami anxiety berlebihan menjelang PTS.','Teknik relaksasi dan manajemen stres.','2026-10-19','2026-05-12 07:12:04'),(8,1,1037,'Karir','Minat Mengikuti Olimpiade Sains','Siswa ingin mengikuti OSN Fisika tingkat provinsi.','Koordinasi dengan guru pembina dan jadwal latihan.','2026-10-22','2026-05-12 07:12:04'),(9,1,1261,'Akademik','Kesulitan Memahami Materi Matematika','Siswa mengalami kesulitan dalam memahami konsep integral. Perlu pendampingan tambahan.','Koordinasi dengan guru mapel untuk les tambahan.','2026-10-01','2026-05-12 07:17:28'),(10,1,1274,'Sosial','Konflik dengan Teman Sekelas','Terjadi kesalahpahaman dengan teman satu kelas terkait tugas kelompok.','Mediasi antara kedua pihak dan pembinaan komunikasi.','2026-10-04','2026-05-12 07:17:28'),(11,1,1287,'Pribadi','Motivasi Belajar Menurun','Siswa terlihat kurang semangat dan sering mengantuk di kelas.','Konseling individu dan koordinasi dengan orang tua.','2026-10-07','2026-05-12 07:17:28'),(12,1,1300,'Karir','Konsultasi Pemilihan Jurusan Kuliah','Siswa bingung memilih antara jurusan teknik atau kedokteran.','Tes minat bakat dan diskusi prospek karir.','2026-10-10','2026-05-12 07:17:28'),(13,1,1313,'Akademik','Nilai Ulangan Harian Menurun','Prestasi akademik menurun sejak semester ini.','Evaluasi metode belajar dan penjadwalan ulang.','2026-10-13','2026-05-12 07:17:28'),(14,1,1326,'Sosial','Kesulitan Beradaptasi di Kelas Baru','Siswa pindahan merasa kesulitan bergaul dengan teman baru.','Buddy system dan kegiatan ice breaking.','2026-10-16','2026-05-12 07:17:28'),(15,1,1339,'Pribadi','Kecemasan Menghadapi Ujian','Siswa mengalami anxiety berlebihan menjelang PTS.','Teknik relaksasi dan manajemen stres.','2026-10-19','2026-05-12 07:17:28'),(16,1,1352,'Karir','Minat Mengikuti Olimpiade Sains','Siswa ingin mengikuti OSN Fisika tingkat provinsi.','Koordinasi dengan guru pembina dan jadwal latihan.','2026-10-22','2026-05-12 07:17:28'),(17,1,1576,'Akademik','Kesulitan Memahami Materi Matematika','Siswa mengalami kesulitan dalam memahami konsep integral. Perlu pendampingan tambahan.','Koordinasi dengan guru mapel untuk les tambahan.','2026-10-01','2026-05-12 07:24:06'),(18,1,1589,'Sosial','Konflik dengan Teman Sekelas','Terjadi kesalahpahaman dengan teman satu kelas terkait tugas kelompok.','Mediasi antara kedua pihak dan pembinaan komunikasi.','2026-10-04','2026-05-12 07:24:06'),(19,1,1602,'Pribadi','Motivasi Belajar Menurun','Siswa terlihat kurang semangat dan sering mengantuk di kelas.','Konseling individu dan koordinasi dengan orang tua.','2026-10-07','2026-05-12 07:24:06'),(20,1,1615,'Karir','Konsultasi Pemilihan Jurusan Kuliah','Siswa bingung memilih antara jurusan tek